func solve(s string, order []int64, k int64) int64 {
    n := int64(len(s))
    if k > n*(n+1)/2 {
        return -1
    }

    modified := make([]bool, n)
    var count int64
    var t int64

    for t = 0; t < n; t++ {
        pos := order[t]
        if !modified[pos] {
            modified[pos] = true
            left := pos
            for left > 0 && !modified[left-1] {
                left--
            }
            right := pos
            for right < n-1 && !modified[right+1] {
                right++
            }
            // The number of new valid substrings introduced by this '*' is (pos - left + 1) * (right - pos + 1)
            count += (pos - left + 1) * (right - pos + 1)
            if count >= k {
                return t + 1
            }
        }
    }

    if count >= k {
        return n
    }
    return -1
}
